import{_ as a,o as t,c as i,aB as s}from"./chunks/framework.Bi5A6EOb.js";const g=JSON.parse('{"title":"Surfaces","description":"","frontmatter":{},"headers":[],"relativePath":"pages/Surfaces/Overview.md","filePath":"pages/Surfaces/Overview.md","lastUpdated":null}'),r={name:"pages/Surfaces/Overview.md"};function l(n,e,d,c,o,p){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="Surfaces" tabindex="-1">Surfaces <a class="header-anchor" href="#Surfaces" aria-label="Permalink to &quot;Surfaces {#Surfaces}&quot;">​</a></h1><p><strong>For:</strong> users selecting a lower-boundary BRDF and developers adding new surface models.</p><p><strong>Next:</strong> <a href="./../extending/surfaces">Add a Surface BRDF</a>, <a href="./../tutorials/Tutorial_Surfaces">Surfaces tutorial</a>, <a href="./../api_reference">Library</a>.</p><p>Surface models live in <code>CoreRT</code> because they are part of the lower-boundary interaction in the adding-doubling solver. Scene files refer to them through safe parser entries such as <code>LambertianSurfaceScalar(0.15)</code>.</p><h2 id="Scene-File-Surface-Tags" tabindex="-1">Scene File Surface Tags <a class="header-anchor" href="#Scene-File-Surface-Tags" aria-label="Permalink to &quot;Scene File Surface Tags {#Scene-File-Surface-Tags}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tag</th><th style="text-align:right;">Arguments</th><th style="text-align:right;">Use case</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>LambertianSurfaceScalar(albedo)</code></td><td style="text-align:right;">scalar albedo</td><td style="text-align:right;">Band-wide isotropic surface</td><td style="text-align:right;">Analytical surface Jacobian</td></tr><tr><td style="text-align:right;"><code>LambertianSurfaceSpectrum([a1, a2, ...])</code></td><td style="text-align:right;">spectral albedo vector</td><td style="text-align:right;">Per-grid-point isotropic surface</td><td style="text-align:right;">Vector length must match the spectral grid</td></tr><tr><td style="text-align:right;"><code>LambertianSurfaceLegendre([c0, c1, ...])</code></td><td style="text-align:right;">Legendre coefficients</td><td style="text-align:right;">Smooth spectral albedo parameterization</td><td style="text-align:right;">Evaluated over the spectral grid</td></tr><tr><td style="text-align:right;"><code>rpvSurfaceScalar(rho0, rho_c, k, Theta)</code></td><td style="text-align:right;">RPV empirical BRDF parameters</td><td style="text-align:right;">Scalar land BRDF with hotspot/angular shape</td><td style="text-align:right;">Scalar only</td></tr><tr><td style="text-align:right;"><code>RossLiSurfaceScalar(fvol, fgeo, fiso)</code></td><td style="text-align:right;">Ross-Li kernel weights</td><td style="text-align:right;">MODIS/RAMI-style land BRDF</td><td style="text-align:right;">Scalar only</td></tr><tr><td style="text-align:right;"><code>CoxMunkSurface(wind_speed)</code></td><td style="text-align:right;">10 m wind speed in <code>m/s</code></td><td style="text-align:right;">Ocean glint and polarization</td><td style="text-align:right;">Uses built-in water refractive-index lookup unless overridden</td></tr><tr><td style="text-align:right;"><code>CoxMunkSurface(wind_speed=U)</code></td><td style="text-align:right;">keyword form</td><td style="text-align:right;">Ocean glint with optional keyword extensions</td><td style="text-align:right;">Supports <code>n_water</code>, <code>whitecap_albedo</code>, <code>include_whitecaps</code>, <code>shadowing</code></td></tr></tbody></table><p>Example:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">radiative_transfer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  surface</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">LambertianSurfaceScalar(0.15)</span></span></code></pre></div><h2 id="Canopy-Wrapper" tabindex="-1">Canopy Wrapper <a class="header-anchor" href="#Canopy-Wrapper" aria-label="Permalink to &quot;Canopy Wrapper {#Canopy-Wrapper}&quot;">​</a></h2><p>Vegetation canopies are configured through an optional top-level <code>canopy:</code> section. The parser wraps each band surface in <code>CanopySurface</code>, so the existing surface becomes the soil BRDF unless a separate canopy soil tag is supplied.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">canopy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  LAI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3.0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  n_layers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  leaf_reflectance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.4</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  leaf_transmittance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.05</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  soil</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">from_surface</span></span></code></pre></div><p>Internally the canopy is treated as scattering sub-layers above the soil boundary and is combined with the same adding-doubling interaction machinery used by the atmospheric column. The current canopy BRDF path is elastic-only.</p><h2 id="Implementation-Map" tabindex="-1">Implementation Map <a class="header-anchor" href="#Implementation-Map" aria-label="Permalink to &quot;Implementation Map {#Implementation-Map}&quot;">​</a></h2><ul><li><p>Surface types are defined in <code>src/CoreRT/types.jl</code>.</p></li><li><p>Surface layer construction lives under <code>src/CoreRT/Surfaces/</code>.</p></li><li><p>Scene-file parsing is registered in <code>BRDF_MAP</code> in <code>src/IO/Parameters.jl</code>.</p></li><li><p>New surface types should add a concrete <code>AbstractSurfaceType</code>, a <code>create_surface_layer!</code>/<code>reflectance</code> implementation as appropriate, and a parser registration.</p></li></ul><h2 id="Useful-APIs" tabindex="-1">Useful APIs <a class="header-anchor" href="#Useful-APIs" aria-label="Permalink to &quot;Useful APIs {#Useful-APIs}&quot;">​</a></h2><ul><li><p><code>AbstractSurfaceType</code></p></li><li><p><code>LambertianSurfaceScalar</code>, <code>LambertianSurfaceSpectrum</code>, <code>LambertianSurfaceLegendre</code>, <code>LambertianSurfaceSpline</code></p></li><li><p><code>rpvSurfaceScalar</code>, <code>RossLiSurfaceScalar</code>, <code>CoxMunkSurface</code></p></li><li><p><code>CanopySurface</code>, <code>CanopySurface_from_prospect</code>, <code>create_surface_layer!</code></p></li></ul>`,16)])])}const u=a(r,[["render",l]]);export{g as __pageData,u as default};
